  `updated_by` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `last_accessed` datetime DEFAULT NULL,
  `access_count` int DEFAULT NULL,
  `expires_at` datetime DEFAULT NULL,
